// Authenticated Fetch Wrapper
async function authenticatedFetch(url, options = {}, refreshTokenFn) {
  let accessToken = TokenStorage.getAccessToken();

  if (TokenStorage.isTokenExpired() && TokenStorage.getRefreshToken()) {
    try {
      const tokens = await refreshTokenFn();
      accessToken = tokens.access_token;
    } catch (error) {
      TokenStorage.clearTokens();
      throw new Error('Session expired. Please login again.');
    }
  }

  if (!accessToken) {
    throw new Error('No access token available. Please login.');
  }

  const headers = {
    Authorization: `Bearer ${accessToken}`,
    'Content-Type': 'application/json',
    ...options.headers,
  };

  const response = await fetch(url.startsWith('http') ? url : `${OAUTH_CONFIG.apiBaseUrl}${url}`, {
    ...options,
    headers,
  });

  if (response.status === 401 && TokenStorage.getRefreshToken()) {
    try {
      const tokens = await refreshTokenFn();
      headers.Authorization = `Bearer ${tokens.access_token}`;
      return fetch(url.startsWith('http') ? url : `${OAUTH_CONFIG.apiBaseUrl}${url}`, {
        ...options,
        headers,
      });
    } catch (error) {
      TokenStorage.clearTokens();
      throw new Error('Session expired. Please login again.');
    }
  }

  return response;
}

