// Callback Page
function CallbackPage() {
  const { exchangeCodeForTokens, fetchUserProfile } = useAuth();
  const { searchParams, navigate } = useRouter();
  const [error, setError] = useState(null);
  const [processing, setProcessing] = useState(true);

  useEffect(() => {
    const handleCallback = async () => {
      const code = searchParams.get('code');
      const state = searchParams.get('state');
      const errorParam = searchParams.get('error');
      const errorDescription = searchParams.get('error_description');

      if (errorParam) {
        setError(errorDescription || errorParam);
        setProcessing(false);
        return;
      }

      if (!code || !state) {
        setError('Missing authorization code or state parameter');
        setProcessing(false);
        return;
      }

      try {
        await exchangeCodeForTokens(code, state);
        await fetchUserProfile();

        // Clean up URL
        window.history.replaceState(null, '', '/');
        navigate('/dashboard');
      } catch (err) {
        setError(err.message);
        setProcessing(false);
      }
    };

    handleCallback();
  }, [searchParams, exchangeCodeForTokens, fetchUserProfile, navigate]);

  if (error) {
    return React.createElement(
      'div',
      { style: { ...styles.app, display: 'flex', flexDirection: 'column', justifyContent: 'center' } },
      React.createElement(
        'div',
        { style: styles.card },
        React.createElement(
          'div',
          { style: { textAlign: 'center', marginBottom: '16px', fontSize: '48px' } },
          '❌'
        ),
        React.createElement('h2', { style: { textAlign: 'center', color: '#1a1a1a' } }, 'Authentication Failed'),
        React.createElement('div', { style: styles.error }, error),
        React.createElement(
          'button',
          {
            style: { ...styles.button, ...styles.primaryButton },
            onClick: () => navigate('/'),
          },
          'Back to Login'
        )
      )
    );
  }

  if (processing) {
    return React.createElement(LoadingScreen, { message: 'Completing authentication...' });
  }

  return null;
}

