// API Test Page
function ApiTestPage() {
  const { apiFetch } = useAuth();
  const { navigate } = useRouter();
  const [endpoint, setEndpoint] = useState('/userinfo');
  const [method, setMethod] = useState('GET');
  const [requestBody, setRequestBody] = useState('');
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [apiError, setApiError] = useState(null);

  const handleRequest = async () => {
    setLoading(true);
    setApiError(null);
    setResult(null);

    try {
      const options = { method };
      if (method !== 'GET' && method !== 'HEAD' && requestBody) {
        options.body = requestBody;
      }

      const response = await apiFetch(endpoint, options);
      const contentType = response.headers.get('content-type') || '';

      let data;
      if (contentType.includes('application/json')) {
        data = await response.json();
      } else {
        data = await response.text();
      }

      setResult({
        status: response.status,
        statusText: response.statusText,
        headers: Object.fromEntries(response.headers.entries()),
        data,
      });
    } catch (err) {
      setApiError(err.message);
    } finally {
      setLoading(false);
    }
  };

  return React.createElement(
    'div',
    { style: styles.app },
    React.createElement(
      'div',
      { style: styles.header },
      React.createElement(
        'button',
        {
          style: {
            border: 'none',
            backgroundColor: 'transparent',
            color: '#007AFF',
            fontSize: '16px',
            cursor: 'pointer',
            padding: '4px',
          },
          onClick: () => navigate('/dashboard'),
        },
        '← Back'
      ),
      React.createElement('h1', { style: styles.headerTitle }, 'API Test')
    ),
    React.createElement(
      'div',
      { style: styles.card },
      React.createElement(
        'div',
        { style: { display: 'flex', gap: '8px', marginBottom: '12px' } },
        React.createElement(
          'select',
          {
            value: method,
            onChange: (e) => setMethod(e.target.value),
            style: {
              padding: '10px',
              borderRadius: '8px',
              border: '1px solid #E5E5EA',
              fontSize: '14px',
              backgroundColor: '#F2F2F7',
            },
          },
          ['GET', 'POST', 'PUT', 'PATCH', 'DELETE'].map((m) =>
            React.createElement('option', { key: m, value: m }, m)
          )
        ),
        React.createElement('input', {
          type: 'text',
          value: endpoint,
          onChange: (e) => setEndpoint(e.target.value),
          placeholder: '/api/endpoint',
          style: {
            flex: 1,
            padding: '10px',
            borderRadius: '8px',
            border: '1px solid #E5E5EA',
            fontSize: '14px',
          },
        })
      ),
      method !== 'GET' &&
        React.createElement('textarea', {
          value: requestBody,
          onChange: (e) => setRequestBody(e.target.value),
          placeholder: 'Request body (JSON)',
          rows: 3,
          style: {
            width: '100%',
            padding: '10px',
            borderRadius: '8px',
            border: '1px solid #E5E5EA',
            fontSize: '14px',
            fontFamily: 'monospace',
            resize: 'vertical',
            marginBottom: '12px',
            boxSizing: 'border-box',
          },
        }),
      React.createElement(
        'button',
        {
          style: {
            ...styles.button,
            ...styles.primaryButton,
            opacity: loading ? 0.6 : 1,
          },
          onClick: handleRequest,
          disabled: loading,
        },
        loading ? 'Sending...' : 'Send Request'
      )
    ),
    apiError && React.createElement('div', { style: { ...styles.card, ...styles.error } }, apiError),
    result &&
      React.createElement(
        'div',
        { style: styles.card },
        React.createElement(
          'div',
          {
            style: {
              display: 'flex',
              justifyContent: 'space-between',
              marginBottom: '12px',
            },
          },
          React.createElement('div', { style: styles.label }, 'Response'),
          React.createElement(
            'span',
            {
              style: {
                color: result.status < 400 ? '#34C759' : '#FF3B30',
                fontWeight: '600',
                fontSize: '14px',
              },
            },
            `${result.status} ${result.statusText}`
          )
        ),
        React.createElement(
          'div',
          { style: styles.apiResult },
          typeof result.data === 'object' ? JSON.stringify(result.data, null, 2) : result.data
        )
      ),
    React.createElement(BottomNav, { active: 'api' })
  );
}

// Bottom Navigation
function BottomNav({ active }) {
  const { navigate } = useRouter();

  const items = [
    { id: 'dashboard', label: 'Home', icon: '🏠', path: '/dashboard' },
    { id: 'api', label: 'API', icon: '🔗', path: '/api-test' },
    { id: 'tokens', label: 'Tokens', icon: '🔑', path: '/tokens' },
    { id: 'profile', label: 'Profile', icon: '👤', path: '/profile' },
  ];

  return React.createElement(
    'div',
    { style: styles.navBar },
    items.map((item) =>
      React.createElement(
        'button',
        {
          key: item.id,
          style: {
            ...styles.navItem,
            ...(active === item.id ? styles.navItemActive : {}),
          },
          onClick: () => navigate(item.path),
        },
        React.createElement('span', { style: { fontSize: '24px', marginBottom: '2px' } }, item.icon),
        item.label
      )
    )
  );
}

// Protected Route wrapper
function ProtectedRoute({ children }) {
  const { isAuthenticated, isLoading } = useAuth();

  if (isLoading) {
    return React.createElement(LoadingScreen, { message: 'Checking authentication...' });
  }

  if (!isAuthenticated) {
    return React.createElement(LoginPage, null);
  }

  return children;
}

// Main App Router
function AppRouter() {
  const { path } = useRouter();

  if (path === '/callback') {
    return React.createElement(CallbackPage, null);
  }

  if (path === '/dashboard') {
    return React.createElement(
      ProtectedRoute,
      null,
      React.createElement(DashboardPage, null)
    );
  }

  if (path === '/profile') {
    return React.createElement(
      ProtectedRoute,
      null,
      React.createElement(ProfilePage, null)
    );
  }

  if (path === '/tokens') {
    return React.createElement(
      ProtectedRoute,
      null,
      React.createElement(TokenInfoPage, null)
    );
  }

  if (path === '/api-test') {
    return React.createElement(
      ProtectedRoute,
      null,
      React.createElement(ApiTestPage, null)
    );
  }

  // Default: redirect authenticated users to dashboard, otherwise show login
  return React.createElement(
    ProtectedRoute,
    null,
    React.createElement(DashboardPage, null)
  );
}

// Root App Component
function App() {
  return React.createElement(AuthProvider, null, React.createElement(AppRouter, null));
}

// Mount the application
const rootElement = document.getElementById('root');
if (rootElement) {
  const root = ReactDOM.createRoot(rootElement);
  root.render(React.createElement(App, null));
}

export { App, AuthProvider, useAuth, authenticatedFetch, TokenStorage, OAUTH_CONFIG };
export default App;